stabilizers = [s.strip() for s in raw.split(',')]
print(f'Number of stabilizers: {len(stabilizers)}')
print(f'Qubit count: {len(stabilizers[0])}')

# Parse stabilizers into Stim format
def to_stim_pauli(s):
    """Convert stabilizer string to stim.PauliString"""
    result = ['+']
    for c in s:
        if c == 'I':
            result.append('_')
        else:
            result.append(c)
    return stim.PauliString(''.join(result))

stim_stabs = [to_stim_pauli(s) for s in stabilizers]

# Create tableau from stabilizers
try:
    tableau = stim.Tableau.from_stabilizers(
        stim_stabs, 
        allow_redundant=True, 
        allow_underconstrained=True
    )
    print("Tableau created successfully")
    
    # Generate circuit using graph_state method (produces CZ gates)
    circuit = tableau.to_circuit(method='graph_state')
    print(f"Circuit generated with {len(circuit)} operations")
    
    # Post-process: RX gates may be introduced for X stabilizers
    # Replace RX with H if starting from |0>
    new_circuit = stim.Circuit()
    for inst in circuit:
        if inst.name == 'RX':
            # RX on |0> gives |+>, which is same as H|0>
            for t in inst.targets_copy():
                new_circuit.append('H', [t.value])
        else:
            new_circuit.append(inst.name, inst.targets_copy(), inst.gate_args_copy())
    
    circuit = new_circuit
    print(f"Final circuit has {len(circuit)} operations")
    print(circuit)
    
    # Save the circuit
    with open('data/claude-opus-4.6/agent_files/candidate_75.stim', 'w') as f:
        f.write(str(circuit))
        
except Exception as e:
    print(f"Error: {e}")
    import traceback
    traceback.print_exc()
